     1вҶ’"use client";
     2вҶ’
     3вҶ’import { useState } from "react";
     4вҶ’import useSWR from "swr";
     5вҶ’import Link from "next/link";
     6вҶ’import {
     7вҶ’  projects as projectsApi,
     8вҶ’  releases as releasesApi,
     9вҶ’  semanticReleases as srApi,
    10вҶ’  sources as sourcesApi,
    11вҶ’} from "@/lib/api/client";
    12вҶ’import { getProviderIcon } from "@/components/ui/provider-badge";
    13вҶ’import { timeAgo } from "@/lib/format";
    14вҶ’import { Plus } from "lucide-react";
    15вҶ’import type { Project } from "@/lib/api/types";
    16вҶ’
    17вҶ’const CHUNK_SIZE = 3;
    18вҶ’
    19вҶ’function ReleaseChips({ projectId }: { projectId: string }) {
    20вҶ’  const [limit, setLimit] = useState(CHUNK_SIZE);
    21вҶ’  const { data } = useSWR(
    22вҶ’    `projects/${projectId}/releases?limit=${limit + 1}`,
    23вҶ’    () => releasesApi.listByProject(projectId, 1, limit + 1)
    24вҶ’  );
    25вҶ’  const { data: sourcesData } = useSWR(
    26вҶ’    `projects/${projectId}/sources`,
    27вҶ’    () => sourcesApi.listByProject(projectId)
    28вҶ’  );
    29вҶ’  const items = data?.data ?? [];
    30вҶ’  const hasMore = items.length > limit;
    31вҶ’  const shown = items.slice(0, limit);
    32вҶ’
    33вҶ’  const providerMap = new Map<string, string>();
    34вҶ’  for (const s of sourcesData?.data ?? []) {
    35вҶ’    providerMap.set(s.id, s.provider);
    36вҶ’  }
    37вҶ’
    38вҶ’  if (!data) return <span className="text-[12px] text-[#c4c4c0] italic">loadingвҖҰ</span>;
    39вҶ’  if (shown.length === 0) return <span className="text-[12px] text-[#c4c4c0]">вҖ”</span>;
    40вҶ’
    41вҶ’  return (
    42вҶ’    <div className="flex flex-wrap items-center gap-1">
    43вҶ’      {shown.map((r) => {
    44вҶ’        const provider = providerMap.get(r.source_id);
    45вҶ’        const Icon = provider ? getProviderIcon(provider) : undefined;
    46вҶ’        return (
    47вҶ’          <Link
    48вҶ’            key={r.id}
    49вҶ’            href={`/releases/${r.id}`}
    50вҶ’            className="inline-flex items-center gap-1 rounded px-1.5 py-0.5 text-[12px] leading-none text-[#374151] transition-colors hover:bg-[#e8e8e5]"
    51вҶ’            style={{ backgroundColor: "#f3f3f1", fontFamily: "'JetBrains Mono', monospace" }}
    52вҶ’          >
    53вҶ’            {Icon && <Icon size={11} className="shrink-0 text-[#6b7280]" />}
    54вҶ’            {r.version}
    55вҶ’          </Link>
    56вҶ’        );
    57вҶ’      })}
    58вҶ’      {hasMore && (
    59вҶ’        <button
    60вҶ’          onClick={() => setLimit((n) => n + CHUNK_SIZE)}
    61вҶ’          className="text-[11px] text-[#e8601a] hover:underline"
    62вҶ’          style={{ fontFamily: "var(--font-dm-sans)" }}
    63вҶ’        >
    64вҶ’          moreвҖҰ
    65вҶ’        </button>
    66вҶ’      )}
    67вҶ’    </div>
    68вҶ’  );
    69вҶ’}
    70вҶ’
    71вҶ’function SemanticReleaseChips({ projectId }: { projectId: string }) {
    72вҶ’  const [limit, setLimit] = useState(CHUNK_SIZE);
    73вҶ’  const { data } = useSWR(
    74вҶ’    `projects/${projectId}/sr?limit=${limit + 1}`,
    75вҶ’    () => srApi.list(projectId, 1, limit + 1)
    76вҶ’  );
    77вҶ’  const items = data?.data ?? [];
    78вҶ’  const hasMore = items.length > limit;
    79вҶ’  const shown = items.slice(0, limit);
    80вҶ’
    81вҶ’  if (!data) return <span className="text-[12px] text-[#c4c4c0] italic">loadingвҖҰ</span>;
    82вҶ’  if (shown.length === 0) return <span className="text-[12px] text-[#c4c4c0]">вҖ”</span>;
    83вҶ’
    84вҶ’  return (
    85вҶ’    <div className="flex flex-wrap items-center gap-1">
    86вҶ’      {shown.map((sr) => (
    87вҶ’        <Link
    88вҶ’          key={sr.id}
    89вҶ’          href={`/projects/${projectId}/semantic-releases/${sr.id}`}
    90вҶ’          className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none text-[#1d4ed8] transition-colors hover:bg-[#dbeafe]"
    91вҶ’          style={{ backgroundColor: "#eff6ff", fontFamily: "'JetBrains Mono', monospace" }}
    92вҶ’        >
    93вҶ’          {sr.version}
    94вҶ’        </Link>
    95вҶ’      ))}
    96вҶ’      {hasMore && (
    97вҶ’        <button
    98вҶ’          onClick={() => setLimit((n) => n + CHUNK_SIZE)}
    99вҶ’          className="text-[11px] text-[#e8601a] hover:underline"
   100вҶ’          style={{ fontFamily: "var(--font-dm-sans)" }}
   101вҶ’        >
   102вҶ’          moreвҖҰ
   103вҶ’        </button>
   104вҶ’      )}
   105вҶ’    </div>
   106вҶ’  );
   107вҶ’}
   108вҶ’
   109вҶ’function ProjectRow({ project, index }: { project: Project; index: number }) {
   110вҶ’  return (
   111вҶ’    <tr
   112вҶ’      className="transition-colors duration-100 hover:bg-[#fafaf9]"
   113вҶ’      style={index > 0 ? { borderTop: "1px solid #e8e8e5" } : undefined}
   114вҶ’    >
   115вҶ’      <td className="px-4 py-2.5">
   116вҶ’        <Link
   117вҶ’          href={`/projects/${project.id}`}
   118вҶ’          className="font-medium text-[#e8601a] hover:underline"
   119вҶ’        >
   120вҶ’          {project.name}
   121вҶ’        </Link>
   122вҶ’      </td>
   123вҶ’      <td className="max-w-[220px] truncate px-4 py-2.5 text-[#6b7280]">
   124вҶ’        {project.description || "вҖ”"}
   125вҶ’      </td>
   126вҶ’      <td className="px-4 py-2.5">
   127вҶ’        <ReleaseChips projectId={project.id} />
   128вҶ’      </td>
   129вҶ’      <td className="px-4 py-2.5">
   130вҶ’        <SemanticReleaseChips projectId={project.id} />
   131вҶ’      </td>
   132вҶ’      <td className="px-4 py-2.5 text-[12px] text-[#9ca3af]">
   133вҶ’        {timeAgo(project.created_at)}
   134вҶ’      </td>
   135вҶ’    </tr>
   136вҶ’  );
   137вҶ’}
   138вҶ’
   139вҶ’export default function ProjectsPage() {
   140вҶ’  const { data, isLoading } = useSWR("projects", () => projectsApi.list());
   141вҶ’  const items = data?.data ?? [];
   142вҶ’
   143вҶ’  return (
   144вҶ’    <div className="flex flex-col gap-4 fade-in">
   145вҶ’      <div className="flex items-center justify-between">
   146вҶ’        <div>
   147вҶ’          <h1
   148вҶ’            style={{
   149вҶ’              fontFamily: "var(--font-fraunces)",
   150вҶ’              fontSize: "24px",
   151вҶ’              fontWeight: 700,
   152вҶ’              color: "#111113",
   153вҶ’            }}
   154вҶ’          >
   155вҶ’            Projects
   156вҶ’          </h1>
   157вҶ’          <p
   158вҶ’            className="mt-1 text-[13px] text-[#6b7280]"
   159вҶ’            style={{ fontFamily: "var(--font-dm-sans)" }}
   160вҶ’          >
   161вҶ’            Tracked software projects and their recent releases.
   162вҶ’          </p>
   163вҶ’        </div>
   164вҶ’        <Link
   165вҶ’          href="/projects/new"
   166вҶ’          className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   167вҶ’          style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   168вҶ’        >
   169вҶ’          <Plus className="h-3.5 w-3.5" />
   170вҶ’          New Project
   171вҶ’        </Link>
   172вҶ’      </div>
   173вҶ’
   174вҶ’      <div
   175вҶ’        className="overflow-hidden rounded-md"
   176вҶ’        style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   177вҶ’      >
   178вҶ’        {isLoading ? (
   179вҶ’          <p
   180вҶ’            className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   181вҶ’            style={{ fontFamily: "var(--font-fraunces)" }}
   182вҶ’          >
   183вҶ’            LoadingвҖҰ
   184вҶ’          </p>
   185вҶ’        ) : items.length === 0 ? (
   186вҶ’          <p
   187вҶ’            className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   188вҶ’            style={{ fontFamily: "var(--font-fraunces)" }}
   189вҶ’          >
   190вҶ’            No projects yet вҖ” create one to start tracking releases
   191вҶ’          </p>
   192вҶ’        ) : (
   193вҶ’          <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans)" }}>
   194вҶ’            <thead>
   195вҶ’              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   196вҶ’                {["Name", "Description", "Recent Releases", "Semantic Releases", "Created"].map(
   197вҶ’                  (h) => (
   198вҶ’                    <th
   199вҶ’                      key={h}
   200вҶ’                      className="px-4 py-2.5 text-left text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   201вҶ’                    >
   202вҶ’                      {h}
   203вҶ’                    </th>
   204вҶ’                  )
   205вҶ’                )}
   206вҶ’              </tr>
   207вҶ’            </thead>
   208вҶ’            <tbody>
   209вҶ’              {items.map((project, i) => (
   210вҶ’                <ProjectRow key={project.id} project={project} index={i} />
   211вҶ’              ))}
   212вҶ’            </tbody>
   213вҶ’          </table>
   214вҶ’        )}
   215вҶ’      </div>
   216вҶ’    </div>
   217вҶ’  );
   218вҶ’}
   219вҶ’

