     1вҶ’"use client";
     2вҶ’
     3вҶ’import { useState } from "react";
     4вҶ’import { useRouter } from "next/navigation";
     5вҶ’import { Button } from "@/components/ui/button";
     6вҶ’import { Input } from "@/components/ui/input";
     7вҶ’import { Label } from "@/components/ui/label";
     8вҶ’import { Textarea } from "@/components/ui/textarea";
     9вҶ’import { Switch } from "@/components/ui/switch";
    10вҶ’import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    11вҶ’import type { Project, ProjectInput } from "@/lib/api/types";
    12вҶ’
    13вҶ’interface ProjectFormProps {
    14вҶ’  initial?: Project;
    15вҶ’  onSubmit: (input: ProjectInput) => Promise<void>;
    16вҶ’  title: string;
    17вҶ’}
    18вҶ’
    19вҶ’export function ProjectForm({ initial, onSubmit, title }: ProjectFormProps) {
    20вҶ’  const router = useRouter();
    21вҶ’  const [saving, setSaving] = useState(false);
    22вҶ’  const [name, setName] = useState(initial?.name ?? "");
    23вҶ’  const [description, setDescription] = useState(initial?.description ?? "");
    24вҶ’  const [agentPrompt, setAgentPrompt] = useState(initial?.agent_prompt ?? "");
    25вҶ’  const [onMajor, setOnMajor] = useState(initial?.agent_rules?.on_major_release ?? true);
    26вҶ’  const [onMinor, setOnMinor] = useState(initial?.agent_rules?.on_minor_release ?? false);
    27вҶ’  const [onSecurity, setOnSecurity] = useState(initial?.agent_rules?.on_security_patch ?? true);
    28вҶ’  const [versionPattern, setVersionPattern] = useState(initial?.agent_rules?.version_pattern ?? "");
    29вҶ’  const [error, setError] = useState("");
    30вҶ’
    31вҶ’  const handleSubmit = async (e: React.FormEvent) => {
    32вҶ’    e.preventDefault();
    33вҶ’    setError("");
    34вҶ’    setSaving(true);
    35вҶ’    try {
    36вҶ’      await onSubmit({
    37вҶ’        name,
    38вҶ’        description: description || undefined,
    39вҶ’        agent_prompt: agentPrompt || undefined,
    40вҶ’        agent_rules: {
    41вҶ’          on_major_release: onMajor,
    42вҶ’          on_minor_release: onMinor,
    43вҶ’          on_security_patch: onSecurity,
    44вҶ’          version_pattern: versionPattern || undefined,
    45вҶ’        },
    46вҶ’      });
    47вҶ’      router.push("/projects");
    48вҶ’    } catch (err: unknown) {
    49вҶ’      setError(err instanceof Error ? err.message : "Failed to save");
    50вҶ’    } finally {
    51вҶ’      setSaving(false);
    52вҶ’    }
    53вҶ’  };
    54вҶ’
    55вҶ’  return (
    56вҶ’    <Card className="mx-auto max-w-2xl">
    57вҶ’      <CardHeader>
    58вҶ’        <CardTitle>{title}</CardTitle>
    59вҶ’      </CardHeader>
    60вҶ’      <CardContent>
    61вҶ’        <form onSubmit={handleSubmit} className="space-y-4">
    62вҶ’          {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    63вҶ’          <div className="space-y-2">
    64вҶ’            <Label htmlFor="name">Name</Label>
    65вҶ’            <Input id="name" value={name} onChange={(e) => setName(e.target.value)} required />
    66вҶ’          </div>
    67вҶ’          <div className="space-y-2">
    68вҶ’            <Label htmlFor="description">Description</Label>
    69вҶ’            <Textarea id="description" value={description} onChange={(e) => setDescription(e.target.value)} rows={2} />
    70вҶ’          </div>
    71вҶ’          <div className="space-y-2">
    72вҶ’            <Label htmlFor="agent_prompt">Agent Prompt</Label>
    73вҶ’            <Textarea
    74вҶ’              id="agent_prompt"
    75вҶ’              value={agentPrompt}
    76вҶ’              onChange={(e) => setAgentPrompt(e.target.value)}
    77вҶ’              rows={6}
    78вҶ’              placeholder="Custom instructions for the agent when analyzing releases for this project..."
    79вҶ’              className="font-mono text-sm"
    80вҶ’            />
    81вҶ’          </div>
    82вҶ’          <div className="space-y-3">
    83вҶ’            <Label>Agent Rules</Label>
    84вҶ’            <div className="rounded-md border p-4 space-y-3">
    85вҶ’              <div className="flex items-center gap-3">
    86вҶ’                <Switch checked={onMajor} onCheckedChange={setOnMajor} />
    87вҶ’                <Label>Trigger on major releases</Label>
    88вҶ’              </div>
    89вҶ’              <div className="flex items-center gap-3">
    90вҶ’                <Switch checked={onMinor} onCheckedChange={setOnMinor} />
    91вҶ’                <Label>Trigger on minor releases</Label>
    92вҶ’              </div>
    93вҶ’              <div className="flex items-center gap-3">
    94вҶ’                <Switch checked={onSecurity} onCheckedChange={setOnSecurity} />
    95вҶ’                <Label>Trigger on security patches</Label>
    96вҶ’              </div>
    97вҶ’              <div className="space-y-2">
    98вҶ’                <Label htmlFor="version_pattern">Version Pattern (regex, optional)</Label>
    99вҶ’                <Input
   100вҶ’                  id="version_pattern"
   101вҶ’                  value={versionPattern}
   102вҶ’                  onChange={(e) => setVersionPattern(e.target.value)}
   103вҶ’                  placeholder='e.g. ^v\d+\.\d+\.\d+$'
   104вҶ’                />
   105вҶ’              </div>
   106вҶ’            </div>
   107вҶ’          </div>
   108вҶ’          <div className="flex justify-end gap-2">
   109вҶ’            <Button type="button" variant="outline" onClick={() => router.back()}>Cancel</Button>
   110вҶ’            <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   111вҶ’          </div>
   112вҶ’        </form>
   113вҶ’      </CardContent>
   114вҶ’    </Card>
   115вҶ’  );
   116вҶ’}
   117вҶ’

