     7вҶ’export function ProjectEdit({ id }: { id: string }) {
     8вҶ’  const { data, isLoading } = useSWR(`project-${id}`, () => projectsApi.get(id));
     9вҶ’
    10вҶ’  if (isLoading) return <div className="py-12 text-center text-muted-foreground">Loading...</div>;
