    21вҶ’/* ---------- Tabs ---------- */
    22вҶ’
    23вҶ’const tabs = [
    24вҶ’  { key: "sources", label: "Sources" },
    25вҶ’  { key: "context", label: "Context Sources" },
    26вҶ’  { key: "semantic", label: "Semantic Releases" },
    27вҶ’  { key: "agent", label: "Agent" },
    28вҶ’] as const;
    29вҶ’
    30вҶ’type TabKey = (typeof tabs)[number]["key"];
    31вҶ’
    32вҶ’/* ---------- Helpers ---------- */
    33вҶ’
    34вҶ’function formatDuration(startedAt?: string, completedAt?: string): string {
    35вҶ’  if (!startedAt) return "--";
    36вҶ’  const start = new Date(startedAt).getTime();
    37вҶ’  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    38вҶ’  const secs = Math.round((end - start) / 1000);
    39вҶ’  if (secs < 60) return `${secs}s`;
    40вҶ’  const mins = Math.floor(secs / 60);
    41вҶ’  const rem = secs % 60;
    42вҶ’  return `${mins}m ${rem}s`;
    43вҶ’}
    44вҶ’
    45вҶ’function truncate(str: string, max: number): string {
    46вҶ’  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    47вҶ’}
    48вҶ’
    49вҶ’function formatInterval(seconds: number): string {
    50вҶ’  if (seconds < 60) return `${seconds}s`;
    51вҶ’  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    52вҶ’  return `${(seconds / 3600).toFixed(1)}h`;
    53вҶ’}
    54вҶ’
    55вҶ’/* ---------- Urgency chip ---------- */
    56вҶ’
    57вҶ’const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    58вҶ’  critical: { bg: "#dc2626", text: "#ffffff" },
    59вҶ’  high: { bg: "#f97316", text: "#ffffff" },
    60вҶ’};
    61вҶ’
    62вҶ’function UrgencyChip({ urgency }: { urgency: string }) {
    63вҶ’  const u = urgency.toLowerCase();
    64вҶ’  const style = URGENCY_COLORS[u];
    65вҶ’  if (!style) return null;
    66вҶ’  return (
    67вҶ’    <span
    68вҶ’      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    69вҶ’      style={{ backgroundColor: style.bg, color: style.text }}
    70вҶ’    >
    71вҶ’      {urgency}
    72вҶ’    </span>
    73вҶ’  );
    74вҶ’}
