   109вҶ’    if (!confirm("Delete this project? This will cascade to sources and subscriptions.")) return;
   110вҶ’    await projectsApi.delete(id);
   111вҶ’    router.push("/projects");
   112вҶ’  };
   113вҶ’
   114вҶ’  const handleTriggerRun = async () => {
   115вҶ’    setTriggering(true);
   116вҶ’    try {
   117вҶ’      await agentApi.triggerRun(id);
   118вҶ’      mutateRuns();
   119вҶ’    } finally {
   120вҶ’      setTriggering(false);
   121вҶ’    }
   122вҶ’  };
   123вҶ’
   124вҶ’  const handleDeleteSource = async (sourceId: string) => {
   125вҶ’    if (!confirm("Delete this source?")) return;
   126вҶ’    await sourcesApi.delete(sourceId);
   127вҶ’    mutateSources();
   128вҶ’  };
   129вҶ’
   130вҶ’  const handleDeleteCtx = async (ctxId: string) => {
