   138вҶ’    setSaving(true);
   139вҶ’    try {
   140вҶ’      const input = {
   141вҶ’        name: project.name,
   142вҶ’        description: project.description,
   143вҶ’        agent_prompt: promptDraft ?? project.agent_prompt,
   144вҶ’        agent_rules: rulesDraft ?? project.agent_rules,
   145вҶ’      };
   146вҶ’      await projectsApi.update(id, input);
   147вҶ’      mutateProject();
   148вҶ’      setPromptDraft(null);
   149вҶ’      setRulesDraft(null);
   150вҶ’    } finally {
   151вҶ’      setSaving(false);
   152вҶ’    }
   153вҶ’  };
   154вҶ’
   155вҶ’  /* Loading / not found states */
