   176вҶ’
   177вҶ’  /* Current effective values */
   178вҶ’  const currentPrompt = promptDraft ?? project.agent_prompt ?? "";
   179вҶ’  const currentRules: AgentRules = rulesDraft ?? project.agent_rules ?? {};
