    78вҶ’export function ProjectDetail({ id }: { id: string }) {
    79вҶ’  const router = useRouter();
    80вҶ’  const [activeTab, setActiveTab] = useState<TabKey>("sources");
    81вҶ’  const [triggering, setTriggering] = useState(false);
