    84вҶ’  const [promptDraft, setPromptDraft] = useState<string | null>(null);
    85вҶ’  const [rulesDraft, setRulesDraft] = useState<AgentRules | null>(null);
    86вҶ’  const [saving, setSaving] = useState(false);
    87вҶ’
    88вҶ’  /* Data fetching */
    89вҶ’  const { data, isLoading, mutate: mutateProject } = useSWR(`project-${id}`, () => projectsApi.get(id));
    90вҶ’  const { data: sourcesData, mutate: mutateSources } = useSWR(
    91вҶ’    activeTab === "sources" ? `project-${id}-sources` : null,
    92вҶ’    () => sourcesApi.listByProject(id),
    93вҶ’  );
    94вҶ’  const { data: ctxData, mutate: mutateCtx } = useSWR(
    95вҶ’    activeTab === "context" ? `project-${id}-ctx` : null,
    96вҶ’    () => ctxApi.list(id),
    97вҶ’  );
    98вҶ’  const { data: srData } = useSWR(
    99вҶ’    activeTab === "semantic" ? `project-${id}-sr` : null,
   100вҶ’    () => srApi.list(id),
